public final class HeaderUtil { private static final String HEADERS_PROPERTY = HeaderUtil . class . getName ( ) + ".HEADERS" ; private HeaderUtil ( ) { } private static Set < QName > getHeaderParts ( BindingMessageInfo bmi ) { Object obj = bmi . getProperty ( HEADERS_PROPERTY ) ; if ( obj == null ) { Set < QName > set = getHeaderQNames ( bmi ) ; bmi . setProperty ( HEADERS_PROPERTY , set ) ; return set ; } return CastUtils . cast ( ( Set < ? > ) obj ) ; } private static Set < QName > getHeaderQNames ( BindingMessageInfo bmi ) { Set < QName > set = new HashSet < QName > ( ) ; List < MessagePartInfo > mps = bmi . getMessageInfo ( ) . getMessageParts ( ) ; List < ExtensibilityElement > extList = bmi . getExtensors ( ExtensibilityElement . class ) ; if ( extList != null ) { for ( ExtensibilityElement ext : extList ) { if ( SOAPBindingUtil . isSOAPHeader ( ext ) ) { SoapHeader header = SOAPBindingUtil . getSoapHeader ( ext ) ; String pn = header . getPart ( ) ; for ( MessagePartInfo mpi : mps ) { if ( pn . equals ( mpi . getName ( ) . getLocalPart ( ) ) ) { if ( mpi . isElement ( ) ) { set . add ( mpi . getElementQName ( ) ) ; } else { set . add ( mpi . getTypeQName ( ) ) ; } break ; } } } } } return set ; } public static Set < QName > getHeaderQNameInOperationParam ( SoapMessage soapMessage ) { BindingOperationInfo bop = soapMessage . getExchange ( ) . getBindingOperationInfo ( ) ; if ( bop != null ) { if ( bop . getInput ( ) != null ) { return getHeaderParts ( bop . getInput ( ) ) ; } if ( bop . getOutput ( ) != null ) { return getHeaderParts ( bop . getOutput ( ) ) ; } } return Collections . emptySet ( ) ; } }